+        assert_eq!(unsafe { fegetround() }, 0xC00);
+
+        // Set to round-down (0x400)
+        assert_eq!(unsafe { fesetround(0x400) }, 0);
+        assert_eq!(unsafe { fegetround() }, 0x400);
+
+        // Restore original
+        assert_eq!(unsafe { fesetround(original) }, 0);
+        assert_eq!(unsafe { fegetround() }, original);
+    }
